import { useState, useCallback } from 'react';
import { Node, Edge, NodeType } from '../types';
import { NODE_TYPES_CONFIG, INITIAL_NODES, INITIAL_EDGES } from '../config';
import { GoogleGenAI, Type } from '@google/genai';

export const useWorkflowGraph = () => {
  const [nodes, setNodes] = useState<Node[]>(INITIAL_NODES);
  const [edges, setEdges] = useState<Edge[]>(INITIAL_EDGES);

  const addNode = useCallback((type: NodeType, x: number, y: number) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newNode: Node = { id, type, x, y, data: { label: NODE_TYPES_CONFIG[type].label } };
    setNodes(prev => [...prev, newNode]);
    return newNode;
  }, []);

  const updateNodeData = useCallback((id: string, data: any) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, data: { ...n.data, ...data } } : n));
  }, []);

  const removeNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setEdges(prev => prev.filter(e => e.sourceId !== id && e.targetId !== id));
  }, []);

  const updateNodePosition = useCallback((id: string, x: number, y: number) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, x, y } : n));
  }, []);

  const addEdge = useCallback((sourceId: string, targetId: string, sourceHandle?: string) => {
    setEdges(prev => {
      if (prev.some(e => e.sourceId === sourceId && e.targetId === targetId && e.sourceHandle === sourceHandle)) return prev;
      return [...prev, {
        id: `e-${sourceId}-${targetId}-${Math.random().toString(36).substr(2, 5)}`,
        sourceId, targetId, sourceHandle
      }];
    });
  }, []);

  return { nodes, edges, setNodes, addNode, updateNodeData, removeNode, updateNodePosition, addEdge };
};

export const useWorkflowRunner = () => {
  const [isExecuting, setIsExecuting] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);
  const [execStates, setExecStates] = useState<Record<string, 'idle' | 'running' | 'completed' | 'error'>>({});

  const clearLogs = () => setLogs([]);

  const log = (msg: string, type: 'info' | 'exec' | 'error' = 'info') => {
    const prefix = type === 'error' ? '[ERROR]' : type === 'exec' ? '[EXEC]' : '[SYSTEM]';
    setLogs(prev => [...prev, `${prefix} ${msg}`]);
  };

  const run = async (nodes: Node[], edges: Edge[]) => {
    setIsExecuting(true);
    setLogs([]);
    setExecStates({});
    log("Initializing Neural Engine...", 'info');

    // Initialize Gemini Client
    let ai: GoogleGenAI;
    try {
        ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        log("Gemini Client Connected.", 'info');
    } catch (e) {
        log("Failed to initialize Gemini Client. Check API Key.", 'error');
        setIsExecuting(false);
        return;
    }

    // Topological Sort / Execution Queue
    const adjacency: Record<string, string[]> = {};
    const inDegree: Record<string, number> = {};
    const nodeMap = new Map(nodes.map(n => [n.id, n]));

    nodes.forEach(n => {
        adjacency[n.id] = [];
        inDegree[n.id] = 0;
    });

    edges.forEach(e => {
        if (adjacency[e.sourceId]) {
            adjacency[e.sourceId].push(e.targetId);
            inDegree[e.targetId] = (inDegree[e.targetId] || 0) + 1;
        }
    });

    const queue: string[] = nodes.filter(n => inDegree[n.id] === 0).map(n => n.id);
    const results: Record<string, { text?: string, images?: string[], audio?: string, json?: any }> = {};

    log(`Execution Plan: ${queue.length} entry points identified.`, 'info');

    while (queue.length > 0) {
        const nodeId = queue.shift()!;
        const node = nodeMap.get(nodeId);

        if (!node) continue;

        setExecStates(prev => ({ ...prev, [nodeId]: 'running' }));
        log(`Processing Node: ${node.data.label}`, 'exec');

        try {
            // Gather Inputs from Parents
            const parentEdges = edges.filter(e => e.targetId === nodeId);
            const inputs = parentEdges.map(e => results[e.sourceId]).filter(Boolean);

            const inputContext = {
                text: inputs.map(i => i.text).filter(Boolean).join('\n\n'),
                images: inputs.flatMap(i => i.images || []),
                audio: inputs.find(i => i.audio)?.audio // Take first audio if exists
            };

            // --- EXECUTION LOGIC PER NODE TYPE ---
            let output: any = {};

            if (node.type === 'start') {
                 // Pass through any static data defined in start node
                 output = { 
                    text: node.data.startText,
                    images: node.data.startImage ? [node.data.startImage] : []
                 };
            }
            else if (node.type === 'textModel') {
                const modelName = node.data.model || 'gemini-3-flash-preview';
                const isThinking = node.data.useThinking;
                const useSearch = node.data.useSearch;
                const useMaps = node.data.useMaps;

                // Model Overrides based on Features
                let activeModel = modelName;
                if (isThinking) activeModel = 'gemini-3-pro-preview';
                if (useMaps) activeModel = 'gemini-2.5-flash';
                if (useSearch && activeModel.includes('2.5')) activeModel = 'gemini-3-flash-preview'; // Upgrade for search if needed

                log(`Invoking ${activeModel}...`, 'info');

                const parts: any[] = [];
                // Add System/Prompt Text
                if (node.data.systemInstruction) {
                    // Implicitly handled by config or just prepend
                }

                // Add Inputs
                if (inputContext.text) parts.push({ text: inputContext.text });

                // Add Node's own prompt if exists
                if (node.data.prompt) parts.push({ text: `User Prompt: ${node.data.prompt}` });

                // Add Images
                inputContext.images.forEach(img => {
                    parts.push({ inlineData: { mimeType: 'image/jpeg', data: img } });
                });

                if (parts.length === 0) parts.push({ text: "Hello!" });

                const config: any = {};

                // Thinking Config
                if (isThinking) {
                    config.thinkingConfig = { thinkingBudget: 32768 };
                    // config.maxOutputTokens is deliberately undefined
                }

                // Tools
                const tools: any[] = [];
                if (useSearch) tools.push({ googleSearch: {} });
                if (useMaps) {
                    tools.push({ googleMaps: {} });
                    // Try to get location
                    try {
                        const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
                             navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
                        });
                        config.toolConfig = {
                            retrievalConfig: {
                                latLng: {
                                    latitude: pos.coords.latitude,
                                    longitude: pos.coords.longitude
                                }
                            }
                        };
                    } catch (e) {
                        log("Location access failed for Maps, using default.", 'info');
                    }
                }
                if (tools.length > 0) config.tools = tools;

                if (node.data.systemInstruction) {
                    config.systemInstruction = node.data.systemInstruction;
                }

                const response = await ai.models.generateContent({
                    model: activeModel,
                    contents: { parts },
                    config
                });

                output.text = response.text;

                // Log Grounding
                if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                    const chunks = response.candidates[0].groundingMetadata.groundingChunks;
                    const urls = chunks.map((c: any) => c.web?.uri || c.maps?.uri).filter(Boolean);
                    if (urls.length > 0) {
                        log(`Sources found: ${urls.slice(0,3).join(', ')}...`, 'info');
                    }
                }
            }
            else if (node.type === 'imageGeneration') {
                log("Generating Image...", 'info');
                const prompt = node.data.prompt || inputContext.text || "A cool futuristic abstract shape";

                // Using gemini-2.5-flash-image for generation via generateContent as per instructions
                // "Call generateContent to generate images with nano banana series models"
                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-image',
                    contents: { parts: [{ text: prompt }] },
                    config: {
                        imageConfig: {
                            aspectRatio: "1:1",
                            imageSize: "1K" // actually only for 3-pro, but harmless to try or omit
                        }
                    }
                });

                let generatedImage = null;
                for (const part of response.candidates?.[0]?.content?.parts || []) {
                    if (part.inlineData) {
                        generatedImage = part.inlineData.data;
                        break;
                    }
                }

                if (generatedImage) {
                    output.images = [generatedImage];
                    output.text = "Image generated successfully.";
                } else {
                    throw new Error("No image returned.");
                }
            }
            else if (node.type === 'audio') {
                // Transcription Node
                log("Transcribing Audio...", 'info');

                // Source: Either input from previous node (if we had audio flow) or Node's internal recording
                const audioData = node.data.audioData; // Base64 string from recording

                if (!audioData) {
                    throw new Error("No audio data found. Please record audio in node properties.");
                }

                const response = await ai.models.generateContent({
                    model: 'gemini-3-flash-preview',
                    contents: {
                        parts: [{
                            inlineData: {
                                mimeType: 'audio/wav', // Assuming recorder saves as wav/webm
                                data: audioData
                            }
                        }, {
                            text: "Transcribe this audio."
                        }]
                    }
                });

                output.text = response.text;
                log(`Transcription: ${response.text.substring(0, 50)}...`, 'info');
            }
            else if (node.type === 'prompt') {
                 // Just a pass-through of text
                 output.text = node.data.content;
            }
            else if (node.type === 'javascript') {
                // Safe-ish eval
                try {
                    // eslint-disable-next-line no-new-func
                    const fn = new Function('input', node.data.code || 'return input;');
                    const result = fn(inputContext.text);
                    output.text = String(result);
                } catch (e: any) {
                    output.text = `Error: ${e.message}`;
                }
            }
            else if (node.type === 'conditional') {
                // Logic evaluation
                let conditionMet = false;
                try {
                   // eslint-disable-next-line no-new-func
                   const check = new Function('text', `return ${node.data.condition || 'true'}`);
                   conditionMet = check(inputContext.text);
                } catch(e) {
                   conditionMet = false;
                }

                output.conditionResult = conditionMet;
                log(`Condition: ${conditionMet}`, 'info');
            }

            results[nodeId] = output;
            setExecStates(prev => ({ ...prev, [nodeId]: 'completed' }));

            // Queue Children
            const outgoing = edges.filter(e => e.sourceId === nodeId);
            outgoing.forEach(edge => {
                 // Check conditional flow
                 if (node.type === 'conditional') {
                     if ((output.conditionResult && edge.sourceHandle === 'true') || 
                         (!output.conditionResult && edge.sourceHandle === 'false')) {
                          inDegree[edge.targetId]--;
                     }
                 } else {
                     inDegree[edge.targetId]--;
                 }

                 if (inDegree[edge.targetId] <= 0) {
                     queue.push(edge.targetId);
                 }
            });

        } catch (error: any) {
            log(`Error in node ${node.data.label}: ${error.message}`, 'error');
            setExecStates(prev => ({ ...prev, [nodeId]: 'error' }));
        }
    }

    log("Workflow Execution Finished.", 'info');
    setIsExecuting(false);
  };

  return { isExecuting, logs, execStates, run, clearLogs };
};

import React, { useState, useRef } from 'react';
import { X, Trash2, AlertTriangle, Mic, Image as ImageIcon, Search, MapPin, BrainCircuit, Zap } from 'lucide-react';
import { Node } from '../types';
import { NODE_TYPES_CONFIG } from '../config';
import { Button, Input, Textarea, Badge } from './ui/Atoms';

interface PropertiesPanelProps {
  selectedNode: Node | undefined;
  updateNodeData: (id: string, data: any) => void;
  removeNode: (id: string) => void;
  onClose: () => void;
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ selectedNode, updateNodeData, removeNode, onClose }) => {
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  if (!selectedNode) return null;
  const config = NODE_TYPES_CONFIG[selectedNode.type];

  // Helper for file reading
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, key: string) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = (reader.result as string).split(',')[1];
        updateNodeData(selectedNode.id, { [key]: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  // Audio Recording Logic
  const toggleRecording = async () => {
    if (isRecording) {
      mediaRecorderRef.current?.stop();
      setIsRecording(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (event) => {
          audioChunksRef.current.push(event.data);
        };

        mediaRecorder.onstop = () => {
          const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
          const reader = new FileReader();
          reader.readAsDataURL(audioBlob);
          reader.onloadend = () => {
             const base64 = (reader.result as string).split(',')[1];
             updateNodeData(selectedNode.id, { audioData: base64 });
          };
          stream.getTracks().forEach(track => track.stop());
        };

        mediaRecorder.start();
        setIsRecording(true);
      } catch (err) {
        console.error("Microphone access denied", err);
        alert("Please allow microphone access to record audio.");
      }
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden animate-enter">
      <div className="p-5 border-b border-[var(--border-subtle)] flex items-center justify-between bg-[var(--bg-glass)]">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded bg-[var(--bg-deep)] border border-[var(--border-subtle)]" style={{ color: config.color }}>
            {React.createElement(config.icon, { size: 16 })}
          </div>
          <div>
            <h3 className="font-bold text-sm text-[var(--fg-primary)]">Properties</h3>
            <div className="text-[10px] text-[var(--fg-secondary)]">{selectedNode.type} • {selectedNode.id.substr(0,4)}</div>
          </div>
        </div>
        <Button variant="ghost" size="icon" onClick={onClose} icon={X} />
      </div>

      <div className="flex-1 overflow-y-auto p-5 space-y-6">
        <div className="space-y-2">
          <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Node Label</label>
          <Input 
            value={selectedNode.data.label} 
            onChange={(e) => updateNodeData(selectedNode.id, { label: e.target.value })} 
            placeholder="Name your step..."
          />
        </div>

        {/* --- START NODE --- */}
        {selectedNode.type === 'start' && (
          <div className="space-y-4 pt-2">
             <div className="text-xs font-semibold text-[var(--accent-primary)] border-b border-[var(--border-subtle)] pb-1">Test Inputs</div>

             <div className="space-y-2">
                <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Initial Text</label>
                <Textarea 
                   value={selectedNode.data.startText || ''}
                   onChange={(e) => updateNodeData(selectedNode.id, { startText: e.target.value })}
                   placeholder="Enter a test prompt to start the flow..."
                />
             </div>

             <div className="space-y-2">
                <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Attach Image</label>
                <div className="flex items-center gap-2">
                   <Input type="file" accept="image/*" onChange={(e) => handleFileChange(e, 'startImage')} />
                </div>
                {selectedNode.data.startImage && (
                   <div className="text-[10px] text-[var(--accent-success)] flex items-center gap-1">
                      <ImageIcon size={10} /> Image attached
                   </div>
                )}
             </div>
          </div>
        )}

        {/* --- TEXT MODEL NODE --- */}
        {selectedNode.type === 'textModel' && (
          <>
            <div className="space-y-2">
              <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">AI Model</label>
              <select 
                className="w-full h-9 rounded-md border border-[var(--border-subtle)] bg-[var(--bg-deep)] px-3 text-sm text-[var(--fg-primary)] focus:border-[var(--accent-primary)] outline-none"
                value={selectedNode.data.model || 'gemini-3-flash-preview'}
                onChange={(e) => updateNodeData(selectedNode.id, { model: e.target.value })}
              >
                <option value="gemini-3-flash-preview">Gemini 3 Flash (Standard)</option>
                <option value="gemini-3-pro-preview">Gemini 3 Pro (High Intellect)</option>
                <option value="gemini-2.5-flash-lite">Gemini 2.5 Flash Lite (Fast)</option>
                <option value="gemini-2.5-flash">Gemini 2.5 Flash (Maps Compatible)</option>
              </select>
            </div>

            <div className="space-y-3 pt-2">
               <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Capabilities</label>

               <div className="flex items-center justify-between p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-deep)]">
                  <div className="flex items-center gap-2 text-xs">
                     <BrainCircuit size={14} className="text-purple-400" /> Thinking Mode
                  </div>
                  <input type="checkbox" 
                     checked={selectedNode.data.useThinking || false}
                     onChange={(e) => updateNodeData(selectedNode.id, { useThinking: e.target.checked })}
                  />
               </div>

               <div className="flex items-center justify-between p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-deep)]">
                  <div className="flex items-center gap-2 text-xs">
                     <Search size={14} className="text-blue-400" /> Google Search
                  </div>
                  <input type="checkbox" 
                     checked={selectedNode.data.useSearch || false}
                     onChange={(e) => updateNodeData(selectedNode.id, { useSearch: e.target.checked })}
                  />
               </div>

               <div className="flex items-center justify-between p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-deep)]">
                  <div className="flex items-center gap-2 text-xs">
                     <MapPin size={14} className="text-red-400" /> Google Maps
                  </div>
                  <input type="checkbox" 
                     checked={selectedNode.data.useMaps || false}
                     onChange={(e) => updateNodeData(selectedNode.id, { useMaps: e.target.checked })}
                  />
               </div>
            </div>

            <div className="space-y-2 mt-4">
               <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">System Instructions</label>
               <Textarea 
                 placeholder="You are a helpful expert..."
                 rows={3}
                 value={selectedNode.data.systemInstruction || ''}
                 onChange={(e) => updateNodeData(selectedNode.id, { systemInstruction: e.target.value })}
               />
            </div>

            <div className="space-y-2">
               <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Additional Prompt</label>
               <Textarea 
                 placeholder="Refine the input..."
                 value={selectedNode.data.prompt || ''}
                 onChange={(e) => updateNodeData(selectedNode.id, { prompt: e.target.value })}
               />
            </div>
          </>
        )}

        {/* --- IMAGE GEN NODE --- */}
        {selectedNode.type === 'imageGeneration' && (
           <div className="space-y-2">
              <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Prompt</label>
              <Textarea 
                 placeholder="Describe the image to generate..."
                 value={selectedNode.data.prompt || ''}
                 onChange={(e) => updateNodeData(selectedNode.id, { prompt: e.target.value })}
              />
              <div className="text-[10px] text-[var(--fg-muted)] italic">Uses Gemini 2.5 Flash Image</div>
           </div>
        )}

        {/* --- AUDIO NODE --- */}
        {selectedNode.type === 'audio' && (
           <div className="space-y-4">
              <div className="space-y-2">
                 <label className="text-[11px] font-bold uppercase tracking-wider text-[var(--fg-muted)]">Audio Source</label>
                 <div className="p-4 rounded border border-[var(--border-subtle)] bg-[var(--bg-deep)] flex flex-col items-center gap-3">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 ${isRecording ? 'bg-red-500/20 animate-pulse' : 'bg-[var(--bg-panel)]'}`}>
                       <Mic size={24} className={isRecording ? 'text-red-500' : 'text-[var(--fg-muted)]'} />
                    </div>
                    <Button 
                       variant={isRecording ? "destructive" : "secondary"} 
                       size="sm"
                       onClick={toggleRecording}
                    >
                       {isRecording ? "Stop Recording" : "Record Microphone"}
                    </Button>
                 </div>
                 {selectedNode.data.audioData && (
                    <div className="text-[10px] text-[var(--accent-success)] flex items-center gap-1 justify-center">
                       <Zap size={10} /> Audio captured successfully
                    </div>
                 )}
              </div>
           </div>
        )}

        {selectedNode.type === 'conditional' && (
           <div className="p-3 rounded border border-[var(--border-subtle)] bg-[var(--bg-deep)] space-y-2">
              <div className="flex items-center gap-2 text-[var(--accent-warning)] text-xs font-bold">
                <AlertTriangle size={12}/> Logic Gate
              </div>
              <p className="text-[10px] text-[var(--fg-muted)]">Executes JavaScript condition on input text.</p>
              <Input 
                className="font-mono text-xs"
                placeholder="text.includes('urgent')"
                value={selectedNode.data.condition}
                onChange={(e) => updateNodeData(selectedNode.id, { condition: e.target.value })}
              />
           </div>
        )}

        <div className="pt-6 border-t border-[var(--border-subtle)]">
           <Button variant="destructive" className="w-full" size="sm" onClick={() => { removeNode(selectedNode.id); onClose(); }} icon={Trash2}>
              Remove Node
           </Button>
        </div>
      </div>
    </div>
  );
};

export default PropertiesPanel;

import React from 'react';
import { Loader2, CheckCircle2, AlertTriangle, BrainCircuit, Search, MapPin, Mic, Image as ImageIcon } from 'lucide-react';
import { Node } from '../types';
import { NODE_TYPES_CONFIG } from '../config';
import { Badge } from './ui/Atoms';

interface WorkflowNodeProps {
  node: Node;
  state: string;
  isSelected: boolean;
  onMouseDown: (e: React.MouseEvent, node: Node) => void;
  onConnectStart: (e: React.MouseEvent, sourceId: string, handleId?: string) => void;
  onConnectEnd: () => void;
}

const WorkflowNode: React.FC<WorkflowNodeProps> = React.memo(({ node, state, isSelected, onMouseDown, onConnectStart, onConnectEnd }) => {
  const config = NODE_TYPES_CONFIG[node.type];

  return (
    <div 
      onMouseDown={(e) => onMouseDown(e, node)}
      onMouseUp={onConnectEnd}
      style={{ left: node.x, top: node.y }}
      className={`
        absolute w-[280px] rounded-xl transition-all duration-300 animate-enter
        flex flex-col bg-[var(--bg-card)]
        ${isSelected 
          ? 'border-2 border-[var(--accent-primary)] shadow-[0_10px_40px_-10px_var(--accent-glow)] z-40 translate-y-[-2px]' 
          : 'border border-[var(--border-subtle)] hover:border-[var(--fg-secondary)] shadow-lg z-10'
        }
        ${state === 'running' ? 'node-running z-50' : ''}
        ${state === 'completed' ? 'border-[var(--accent-success)] shadow-[0_0_20px_var(--accent-success)]' : ''}
        ${state === 'error' ? 'border-[var(--accent-error)] shadow-[0_0_20px_var(--accent-error)]' : ''}
      `}
    >
      {/* Decorative Gradient Top */}
      <div className="h-1 w-full rounded-t-lg opacity-80" style={{ background: `linear-gradient(90deg, ${config.color}, transparent)` }} />

      {/* Header */}
      <div className="p-3 flex items-start gap-3 border-b border-[var(--border-subtle)] bg-[var(--bg-panel)] rounded-t-lg">
          <div className="p-2 rounded-lg bg-[var(--bg-deep)] border border-[var(--border-subtle)] shrink-0" style={{ color: config.color }}>
            {React.createElement(config.icon, { size: 18 })}
          </div>
          <div className="flex-1 min-w-0 flex flex-col justify-center h-9">
            <div className="text-sm font-semibold text-[var(--fg-primary)] truncate leading-tight">{node.data.label}</div>
            <div className="text-[10px] font-mono text-[var(--fg-muted)] uppercase tracking-wide">{config.category} • {config.label}</div>
          </div>
          <div className="shrink-0 flex items-center h-9">
             {state === 'running' && <Loader2 size={16} className="animate-spin text-[var(--accent-primary)]" />}
             {state === 'completed' && <CheckCircle2 size={16} className="text-[var(--accent-success)]" />}
             {state === 'error' && <AlertTriangle size={16} className="text-[var(--accent-error)]" />}
          </div>
      </div>

      {/* Body */}
      <div className="p-4 space-y-2 relative group">
          {node.type === 'httpRequest' && (
            <div className="flex items-center gap-2 text-xs font-mono bg-[var(--bg-deep)] p-2 rounded border border-[var(--border-subtle)]">
              <span className="font-bold text-[var(--accent-primary)]">{node.data.method}</span> 
              <span className="truncate opacity-70">{node.data.url}</span>
            </div>
          )}
          {node.type === 'textModel' && (
             <div className="space-y-2">
                 <div className="text-xs text-[var(--fg-secondary)] flex justify-between items-center">
                    <span className="opacity-50">Model</span>
                    <Badge>{(node.data.model || 'Flash').split('-')[2]}</Badge>
                 </div>
                 <div className="flex gap-1">
                    {node.data.useThinking && <div className="p-1 rounded bg-purple-500/20 text-purple-400" title="Thinking Mode"><BrainCircuit size={12}/></div>}
                    {node.data.useSearch && <div className="p-1 rounded bg-blue-500/20 text-blue-400" title="Google Search"><Search size={12}/></div>}
                    {node.data.useMaps && <div className="p-1 rounded bg-red-500/20 text-red-400" title="Google Maps"><MapPin size={12}/></div>}
                 </div>
             </div>
          )}
          {node.type === 'audio' && (
             <div className="text-xs text-[var(--fg-secondary)] flex items-center gap-2">
                 <Mic size={12} className="text-[var(--accent-primary)]" />
                 {node.data.audioData ? "Audio Recorded" : "No Audio"}
             </div>
          )}
           {node.type === 'imageGeneration' && (
             <div className="text-xs text-[var(--fg-secondary)] flex items-center gap-2">
                 <ImageIcon size={12} className="text-[var(--accent-primary)]" />
                 Gen: Gemini 2.5 Flash
             </div>
          )}
          {node.type === 'prompt' && (
             <div className="text-xs italic text-[var(--fg-muted)] bg-[var(--bg-deep)] p-2 rounded border border-[var(--border-subtle)] line-clamp-2">
               "{node.data.content || 'System prompt...'}"
             </div>
          )}
          {node.type === 'conditional' && (
             <div className="text-xs font-mono text-[var(--accent-primary)] text-center py-1">
               IF {node.data.condition || 'condition'}
             </div>
          )}

          {/* Subtle ID watermark */}
          <div className="absolute bottom-1 right-2 text-[8px] font-mono text-[var(--border-active)] opacity-0 group-hover:opacity-100 transition-opacity">
            ID: {node.id}
          </div>
      </div>

      {/* Handles - Interactive Zones */}
      {/* Input */}
      {node.type !== 'start' && (
        <div className="absolute -left-[6px] top-1/2 -translate-y-1/2 w-6 h-6 flex items-center justify-center cursor-crosshair group-handle" onMouseUp={onConnectEnd}>
          <div className="handle" />
          <div className="absolute left-[-20px] bg-[var(--bg-card)] text-[9px] px-1 py-0.5 rounded border border-[var(--border-subtle)] opacity-0 group-handle-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">Input</div>
        </div>
      )}

      {/* Output */}
      {node.type !== 'end' && node.type !== 'conditional' && (
        <div className="absolute -right-[6px] top-1/2 -translate-y-1/2 w-6 h-6 flex items-center justify-center cursor-crosshair group-handle" onMouseDown={(e) => onConnectStart(e, node.id)}>
          <div className="handle" />
        </div>
      )}

      {/* Conditional Outputs */}
      {node.type === 'conditional' && (
        <>
          <div className="absolute -right-[6px] top-[35px] w-6 h-6 flex items-center justify-center cursor-crosshair group-handle" onMouseDown={(e) => onConnectStart(e, node.id, 'true')}>
             <div className="handle !border-[var(--accent-success)] hover:!bg-[var(--accent-success)]" />
             <div className="absolute right-[-30px] text-[9px] font-bold text-[var(--accent-success)] pointer-events-none">TRUE</div>
          </div>
          <div className="absolute -right-[6px] top-[85px] w-6 h-6 flex items-center justify-center cursor-crosshair group-handle" onMouseDown={(e) => onConnectStart(e, node.id, 'false')}>
             <div className="handle !border-[var(--accent-error)] hover:!bg-[var(--accent-error)]" />
             <div className="absolute right-[-35px] text-[9px] font-bold text-[var(--accent-error)] pointer-events-none">FALSE</div>
          </div>
        </>
      )}
    </div>
  );
});

export default WorkflowNode;
